 31	
 32	static f1_ue_data_t *get_hashtable_data(hash_table_t *ht, uint64_t ue_id)
 33	{
 34	  void *data = NULL;
 35	  hashtable_rc_t ret = hashtable_get(ht, ue_id, &data);
 36	  AssertFatal(ret == HASH_TABLE_OK && data != NULL, "element for ue_id %ld not found\n", ue_id);
 37	  return data;
 38	}
 39	
 40	static bool add_hashtable_data(hash_table_t *ht, uint64_t ue_id, const f1_ue_data_t *data)
 41	{
 42	  f1_ue_data_t *idata = malloc(sizeof(*idata));
 43	  AssertFatal(idata, "cannot allocate memory\n");
 44	  *idata = *data;
 45	  hashtable_rc_t ret = hashtable_insert(ht, ue_id, idata);
 46	  return ret == HASH_TABLE_OK;
 47	}
 48	
 49	/* we have separate versions for CU and DU, as both CU&DU might coexist in the
 50	 * same process */
 51	static hash_table_t *cu2du_ue_mapping;
 52	static pthread_mutex_t cu2du_mutex = PTHREAD_MUTEX_INITIALIZER;
 53	
 54	void cu_init_f1_ue_data(void)
 55	{
 56	  pthread_mutex_lock(&cu2du_mutex);
 57	  DevAssert(cu2du_ue_mapping == NULL);
 58	  cu2du_ue_mapping = hashtable_create(1319, NULL, free); // 1319 is prime, default hash func (unit), free()
 59	  DevAssert(cu2du_ue_mapping != NULL);
 60	  pthread_mutex_unlock(&cu2du_mutex);
 61	}
 62	
 63	bool cu_add_f1_ue_data(uint32_t ue_id, const f1_ue_data_t *data)
 64	{
 65	  pthread_mutex_lock(&cu2du_mutex);
 66	  DevAssert(cu2du_ue_mapping != NULL);
 67	  uint64_t key = ue_id;
 68	  if (hashtable_is_key_exists(cu2du_ue_mapping, key) == HASH_TABLE_OK) {
 69	    pthread_mutex_unlock(&cu2du_mutex);
 70	    return false;
 71	  }
 72	  bool ret = add_hashtable_data(cu2du_ue_mapping, key, data);
 73	  pthread_mutex_unlock(&cu2du_mutex);
 74	  return ret;
 75	}
